        _mm512_store_pd(&out_re[23*K+k], x2r); _mm512_store_pd(&out_im[23*K+k], x2i);
        _mm512_store_pd(&out_re[31*K+k], x3r); _mm512_store_pd(&out_im[31*K+k], x3i);
        _mm512_store_pd(&out_re[39*K+k], x4r); _mm512_store_pd(&out_im[39*K+k], x4i);
        _mm512_store_pd(&out_re[47*K+k], x5r); _mm512_store_pd(&out_im[47*K+k], x5i);
        _mm512_store_pd(&out_re[55*K+k], x6r); _mm512_store_pd(&out_im[55*K+k], x6i);
        _mm512_store_pd(&out_re[63*K+k], x7r); _mm512_store_pd(&out_im[63*K+k], x7i);

